INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1041, 186488, 2, 1552, '最后的挽歌', '房间里开着台灯，郑智化忧伤的歌声飘荡在整个房间“是否记得我骄傲地说，这世界我曾经来过，不要告诉我永恒是什么，我在最灿烂的瞬间毁灭”吴梦静静地坐在沙发上，脸上化了淡淡的妆，昏黄的灯光下显得特别地详和。桌上放着一瓶药和一把刀片，一生中的最后一个晚上，许久以来压在心里的石头终于落下了，或许对她来说是最快乐的时刻。                                                                                                                   她想明天报纸最不显眼的角落里一定有这条新闻，“一女子在家自杀，原因还在调查中。”立人会看到这新闻吗？会知道是她吗？会为她而哭泣吗？这一切她不可能会知道了。人生在世，苦多乐少，这28年来她尝过无数的痛苦，终于可以结束了，立人，你总是说我喜怒无常，可是你知道吗，在我嘻笑怒骂的背后，有多少不为人知的无奈和辛酸，今夜，请你静静地听我说，好吗？                                                         你还记得你说分手的时候，那绝然的神情，如同当年母亲把我送到亲戚家里寄养时，转身离开的模样。立人，我的心再一次脆了。我没有怪过你，当我把以前的事告诉你的时候，我已料到了今日的结局，只是我希望你的眼神有一丝不舍，那么在以后的日子里还有一点值得我回忆的温情，可是，你没有。或许我只是你生命中的一个过客，但你却是我生命的全部啊。当你用温柔的眼神望着我时，我曾经以为那是命运之神对我的眷顾，我那么感激你，是你在我灰暗的生命中给了我一线光明，让我可以忘记往事，重新面对我的人生。                                                                                    立人，我们在一起时，你和我说起你小时候是如何顽皮，如何受到家人的宠爱，你问我小时候是什么样的，我总是笑笑不答，可是，立人，你知道吗，那时的我是多么地羡慕你，因为这是我曾经在梦里向往已久的童年啊！而我又怎能告诉你我是在歧视和嘲笑中长大的， 因为那是我最不愿提及的往事，当父亲去世后，母亲改嫁他乡，把我寄养在叔叔家时，我的童年就已经结束了。终日面对着叔叔严厉的目光，婶婶的冷言冷语，那种寄人离下的感觉，立人，你是无法了解的。我十五岁那年跟随阿风离家出走，他给了我温饱的生活，我也做了他五年的女人，我只是想有个依靠，可是我又一次成了命运的奴隶，任随命运的安排，就象那首歌唱的，“任那雨打风吹也沉默，仿佛是我。”
<br>                    立人，和你分手后，我很后悔，原本可以不告诉你的，可是，我只是想把这十几年来所受的委屈告诉你，我想要你好好地安慰我。然而，我在你的眼神里看到了惊讶、厌恶，我知道 我的美梦破碎了 。立人，今天我选择这条路，不是因为你的离开，而是我已经累了，前面满是荆棘，我没有勇气再走下去，不要怪我懦弱，因为这是我唯一一次可以自己选择的道路。                                                                        
<br>                    吴梦写完了信，天色已经发白，又是新的一天了，许多人会上演着不同的故事，而吴梦的故事也该结束了。“别哭，我最爱的人，今夜我如昙花绽放，在最美的瞬间凋落，你的泪也挽不回的枯萎。”在歌声中她拿起了药瓶。', '房间里开着台灯，郑智化忧伤的歌声飘荡在整个房间“是否记得我骄傲地说，这世界我曾经来过，不要告诉我永恒是什么，我在最灿烂的瞬间毁灭”吴梦静静地坐在沙发上，脸上化了淡淡的妆，昏黄的灯光下显得特别地详和。桌上放着一瓶药和一把刀片，一生中的最后一个晚上，许久以来压在心里的石头终于落下了，或许对她来说是最快乐的时刻。                                                                                                                   她想明天报纸最不显眼的角落里一定有这条新闻，“一女子在家自杀，原因还在调查中。”立人会看到这新闻吗？会知道是她吗？会为她而哭泣吗？这一切她不可能会知道了。人生在世，苦多乐少，这28年来她尝过无数的痛苦，终于可以结束了，立人，你总是说我喜怒无常，可是你知道吗，在我嘻笑怒骂的背后，有多少不为人知的无奈和辛酸，今夜，请你静静地听我说，好吗？                                                         你还记得你说分手的时候，那绝然的神情，如同当年母亲把我送到亲戚家里寄养时，转身离开的模样。立人，我的心再一次脆了。我没有怪过你，当我把以前的事告诉你的时候，我已料到了今日的结局，只是我希望你的眼神有一丝不舍，那么在以后的日子里还有一点值得我回忆的温情，可是，你没有。或许我只是你生命中的一个过客，但你却是我生命的全部啊。当你用温柔的眼神望着我时，我曾经以为那是命运之神对我的眷顾，我那么感激你，是你在我灰暗的生命中给了我一线光明，让我可以忘记往事，重新面对我的人生。                                                                                    立人，我们在一起时，你和我说起你小时候是如何顽皮，如何受到家人的宠爱，你问我小时候是什么样的，我总是笑笑不答，可是，立人，你知道吗，那时的我是多么地羡慕你，因为这是我曾经在梦里向往已久的童年啊！而我又怎能告诉你我是在歧视和嘲笑中长大的， 因为那是我最不愿提及的往事，当父亲去世后，母亲改嫁他乡，把我寄养在叔叔家时，我的童年就已经结束了。终日面对着叔叔严厉的目光，婶婶的冷言冷语，那种寄人离下的感觉，立人，你是无法了解的。我十五岁那年跟随阿风离家出走，他给了我温饱的生活，我也做了他五年的女人，我只是想有个依靠，可是我又一次成了命运的奴隶，任随命运的安排，就象那首歌唱的，“任那雨打风吹也沉默，仿佛是我。”

立人，和你分手后，我很后悔，原本可以不告诉你的，可是，我只是想把这十几年来所受的委屈告诉你，我想要你好好地安慰我。然而，我在你的眼神里看到了惊讶、厌恶，我知道 我的美梦破碎了 。立人，今天我选择这条路，不是因为你的离开，而是我已经累了，前面满是荆棘，我没有勇气再走下去，不要怪我懦弱，因为这是我唯一一次可以自己选择的道路。

吴梦写完了信，天色已经发白，又是新的一天了，许多人会上演着不同的故事，而吴梦的故事也该结束了。“别哭，我最爱的人，今夜我如昙花绽放，在最美的瞬间凋落，你的泪也挽不回的枯萎。”在歌声中她拿起了药瓶。', NULL, '2002-10-19 00:41:00', 2, '20021116150111_bbsid_186488_board_2_a1183d55ab.html', '20021116150111');
